"use client";

import * as React from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";

const schema = z.object({
  name: z.string().min(2, "Please enter your name"),
  email: z.string().email("Please enter a valid email"),
  message: z.string().min(10, "Message must be at least 10 characters"),
});

export type TdContactFormValues = z.infer<typeof schema>;

export interface TdContactFormProps {
  /** Async handler. Receives validated values; resolve to clear the form, reject (throw) to keep values. */
  onSubmit: (values: TdContactFormValues) => Promise<void> | void;
  submitLabel?: string;
  className?: string;
}

export function TdContactForm({
  onSubmit,
  submitLabel = "Send message",
  className = "",
}: TdContactFormProps) {
  const [serverError, setServerError] = React.useState<string | null>(null);
  const [success, setSuccess] = React.useState(false);
  const {
    register,
    handleSubmit,
    reset,
    formState: { errors, isSubmitting },
  } = useForm<TdContactFormValues>({
    resolver: zodResolver(schema),
    defaultValues: { name: "", email: "", message: "" },
  });

  const submit = handleSubmit(async (values) => {
    setServerError(null);
    setSuccess(false);
    try {
      await onSubmit(values);
      setSuccess(true);
      reset();
    } catch (err) {
      setServerError(err instanceof Error ? err.message : "Could not send message");
    }
  });

  const labelCls = "text-sm font-medium text-slate-800";
  const inputCls =
    "w-full rounded-md border bg-white px-3 py-2 text-base text-slate-900 shadow-sm focus:outline-none focus:ring-2 focus:ring-[var(--td-primary,#2E6554)] focus:border-transparent";
  const errCls = "text-xs";

  return (
    <form
      onSubmit={submit}
      className={`flex flex-col gap-5 ${className}`.trim()}
      noValidate
    >
      <div className="flex flex-col gap-1.5">
        <label htmlFor="td-cf-name" className={labelCls}>
          Name
        </label>
        <input
          id="td-cf-name"
          type="text"
          autoComplete="name"
          className={inputCls}
          style={{ borderColor: "var(--td-border, rgba(15,23,42,0.15))" }}
          {...register("name")}
        />
        {errors.name ? (
          <span className={errCls} style={{ color: "#b91c1c" }}>{errors.name.message}</span>
        ) : null}
      </div>
      <div className="flex flex-col gap-1.5">
        <label htmlFor="td-cf-email" className={labelCls}>
          Email
        </label>
        <input
          id="td-cf-email"
          type="email"
          autoComplete="email"
          className={inputCls}
          style={{ borderColor: "var(--td-border, rgba(15,23,42,0.15))" }}
          {...register("email")}
        />
        {errors.email ? (
          <span className={errCls} style={{ color: "#b91c1c" }}>{errors.email.message}</span>
        ) : null}
      </div>
      <div className="flex flex-col gap-1.5">
        <label htmlFor="td-cf-message" className={labelCls}>
          Message
        </label>
        <textarea
          id="td-cf-message"
          rows={5}
          className={inputCls}
          style={{ borderColor: "var(--td-border, rgba(15,23,42,0.15))" }}
          {...register("message")}
        />
        {errors.message ? (
          <span className={errCls} style={{ color: "#b91c1c" }}>{errors.message.message}</span>
        ) : null}
      </div>
      {serverError ? (
        <div className="text-sm" style={{ color: "#b91c1c" }}>{serverError}</div>
      ) : null}
      {success ? (
        <div
          className="text-sm"
          style={{ color: "var(--td-primary, #2E6554)" }}
        >
          Thanks. We&apos;ll be in touch shortly.
        </div>
      ) : null}
      <button
        type="submit"
        disabled={isSubmitting}
        className="inline-flex h-11 items-center justify-center rounded-md px-5 text-sm font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-60"
        style={{ backgroundColor: "var(--td-primary, #2E6554)" }}
      >
        {isSubmitting ? "Sending..." : submitLabel}
      </button>
    </form>
  );
}

export default TdContactForm;
